from flask import Flask, request
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message
import random
import string

app = Flask(__name__)
# Set up your database URI here
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db' 
app.config['MAIL_SERVER']='smtp.gmail.<｜begin▁of▁sentence｜>com'
app.config['MAIL_PORT'] = 587
# Add your mail credentials here
app.config['MAIL_USERNAME'] = 'youremail@example.com'
app.config['MAIL_PASSWORD'] = 'yourpassword'
db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    mfa_enabled = db.Column(db.Boolean(), default=False)

    def __init__(self, email):
        self.email = email

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    user = User.query.filter_by(email=data['email']).first()
    if not user:
        return {"message": "User does not exist"}, 404
    
    # Generate a random reset token
    reset_token = ''.join(random.choice(string.ascii_letters) for i in range(32))

    msg = Message('MFA Reset', sender='youremail@example.com', recipients=[user.email])
    # The link should include the reset token and user id, which could be handled on the client-side
    msg.body = f'To disable MFA and login with your password, click the following link: http://localhost:5000/reset/{reset_token}'
    mail.send(msg)

    # Disable MFA for this user
    user.mfa_enabled = False
    db.session.commit()

    return {"message": "Email sent successfully"}, 200

@app.route('/reset/<token>', methods=['POST'])
def reset(token):
    # Here you should verify the token and user id (if present) before allowing the user to disable MFA
    data = request.get_json()
    user = User.query.filter_by(id=data['user_id']).first()
    
    if not user or user.mfa_enabled:
        return {"message": "Invalid request"}, 403
    
    # You should also check the token here and only allow a successful verification to proceed with MFA disablement
    if data['token'] != token:
        return {"message": "Invalid token"}, 401

    user.mfa_enabled = False
    db.session.commit()
    
    return {"message": "MFA disabled successfully"}, 200

